class RoiFailure(RuntimeError):
    """Expected ROI-level failure."""

    def __init__(self, reason: str):
        super().__init__(reason)
        self.reason = reason


@dataclass(frozen=True)
class BBox:
    """Half-open bbox in aligned 224-space: [x1:x2, y1:y2]."""

    x1: int
    y1: int
    x2: int
    y2: int

    @property
    def w(self) -> int:
        return self.x2 - self.x1

    @property
    def h(self) -> int:
        return self.y2 - self.y1

    @property
    def area(self) -> int:
        return max(0, self.w) * max(0, self.h)


@dataclass
class GlobalIntermediates:
    original_rgb: np.ndarray | None
    aligned_rgb: np.ndarray
    label_map: np.ndarray
    selected_semantic_mask: np.ndarray
    final_face_mask: np.ndarray
    aligned_landmarks: np.ndarray | None
    source: str
    input_path: str = ""
    global_status: str = "success"
    global_failure_reason: str = ""
    global_metrics: dict[str, Any] | None = None


@dataclass
class CanvasResult:
    image: np.ndarray
    content_w: int
    content_h: int
    padding_top: int
    padding_bottom: int
    padding_left: int
    padding_right: int

    @property
    def padding_ratio(self) -> float:
        total = float(self.image.shape[0] * self.image.shape[1])
        content = float(self.content_w * self.content_h)
        return 1.0 - content / total

    @property
    def content_ratio(self) -> float:
        return 1.0 - self.padding_ratio


