def _normalize_config_keys(config: dict[str, Any]) -> dict[str, Any]:
    return {str(key).strip().replace("-", "_"): value for key, value in config.items()}


def load_yaml_config(config_path: Path | None, project_root: Path) -> dict[str, Any]:
    if config_path is None:
        config_path = project_root / "config" / "preprocess" / DEFAULT_CONFIG_NAME
    elif not config_path.is_absolute():
        config_path = project_root / config_path
    if not config_path.is_file():
        raise FileNotFoundError(f"Config file does not exist: {config_path}")
    with config_path.open("r", encoding="utf-8") as handle:
        loaded = yaml.safe_load(handle) or {}
    if not isinstance(loaded, dict):
        raise ValueError(f"Config root must be a YAML mapping: {config_path}")
    return _normalize_config_keys(loaded)


def _configurable_keys(parser: argparse.ArgumentParser) -> list[str]:
    excluded = {"help", "config", "project_root"}
    return [
        action.dest
        for action in parser._actions
        if action.dest not in excluded and action.dest != argparse.SUPPRESS
    ]


def parse_args(argv: Sequence[str] | None = None) -> argparse.Namespace:
    parser = build_parser()
    cli = parser.parse_args(argv)
    inferred_root = (
        cli.project_root.expanduser().resolve()
        if cli.project_root is not None
        else default_project_root()
    )
    config = load_yaml_config(cli.config, inferred_root)
    allowed_config_keys = set(_configurable_keys(parser)) | {"project_root"}
    unknown_keys = sorted(set(config).difference(allowed_config_keys))
    if unknown_keys:
        raise ValueError(f"Unsupported config keys in {DEFAULT_CONFIG_NAME}: {unknown_keys}")

    config_root = config.get("project_root")
    if cli.project_root is not None or config_root in (None, "", "."):
        project_root = inferred_root
    else:
        project_root = Path(config_root).expanduser()
        if not project_root.is_absolute():
            project_root = inferred_root / project_root
        project_root = project_root.resolve()

    values: dict[str, Any] = {
        "config": (
            cli.config if cli.config is not None
            else project_root / "config" / "preprocess" / DEFAULT_CONFIG_NAME
        ),
        "project_root": project_root,
    }
    missing: list[str] = []
    for key in _configurable_keys(parser):
        cli_value = getattr(cli, key)
        if cli_value is not None:
            values[key] = cli_value
        elif key in config:
            values[key] = config[key]
        else:
            missing.append(key)
    if missing:
        raise ValueError(
            f"Missing required config keys in {DEFAULT_CONFIG_NAME}: {missing}"
        )
    return argparse.Namespace(**values)


def resolve_path(path: Path | str | None, project_root: Path) -> Path | None:
    if path is None:
        return None
    path = Path(path).expanduser()
    return path if path.is_absolute() else project_root / path


def parse_csv_list(value: str | Sequence[str]) -> list[str]:
    if isinstance(value, (list, tuple)):
        items = [str(item).strip() for item in value if str(item).strip()]
        return items
    items = [item.strip() for item in str(value).split(",") if item.strip()]
    return items


def parse_padding_color(value: str | Sequence[int | float | str]) -> tuple[int, int, int]:
    if isinstance(value, (list, tuple)):
        parts = [int(float(part)) for part in value]
    else:
        parts = [int(float(part.strip())) for part in str(value).split(",")]
    if len(parts) != 3 or any(part < 0 or part > 255 for part in parts):
        raise ValueError("--padding-color must be three RGB values, e.g. 0,0,0")
    return tuple(parts)  # type: ignore[return-value]


def load_split_table(split_csv: Path, max_samples: int | None) -> pd.DataFrame:
    if not split_csv.is_file():
        raise FileNotFoundError(f"Split CSV does not exist: {split_csv}")
    frame = pd.read_csv(split_csv, dtype={"ID": "string"}, encoding="utf-8-sig")
    if "ID" not in frame.columns:
        raise ValueError(f"Split CSV must contain ID column: {split_csv}")
    frame["ID"] = frame["ID"].astype(str)
    if max_samples is not None:
        frame = frame.head(max_samples).copy()
    return frame.reset_index(drop=True)


def prepare_output_dirs(output_dir: Path, overwrite: bool) -> dict[str, Path]:
    if output_dir.exists() and overwrite:
        shutil.rmtree(output_dir)
    output_dir.mkdir(parents=True, exist_ok=True)
    dirs: dict[str, Path] = {
        "root": output_dir,
        "logs": output_dir / "logs",
        "roi_raw": output_dir / "roi_raw",
        "roi_masked": output_dir / "roi_masked",
        "qc_preview": output_dir / "qc_preview",
        "intermediates_optional": output_dir / "intermediates_optional",
    }
    qc_categories = (
        "random_success",
        "core_all_success",
        "roi_failure",
        "high_padding_ratio",
        "eye_roi_warning",
        "lip_roi_warning",
        "cheek_roi_warning",
        "forehead_roi_warning",
        "chin_roi_warning",
    )
    for path in dirs.values():
        path.mkdir(parents=True, exist_ok=True)
    for roi_type in DEFAULT_ROI_TYPES:
        (dirs["roi_raw"] / roi_type).mkdir(parents=True, exist_ok=True)
        (dirs["roi_masked"] / roi_type).mkdir(parents=True, exist_ok=True)
    for category in qc_categories:
        (dirs["qc_preview"] / category).mkdir(parents=True, exist_ok=True)
        dirs[f"qc_{category}"] = dirs["qc_preview"] / category
    for name in (
        "aligned_rgb",
        "parsing_label",
        "selected_semantic_mask",
        "final_face_mask",
    ):
        (dirs["intermediates_optional"] / name).mkdir(parents=True, exist_ok=True)
    return dirs


def read_rgb_png(path: Path) -> np.ndarray:
    data = np.fromfile(str(path), dtype=np.uint8)
    bgr = cv2.imdecode(data, cv2.IMREAD_COLOR)
    if bgr is None:
        raise FileNotFoundError(f"Cannot read image: {path}")
    return cv2.cvtColor(bgr, cv2.COLOR_BGR2RGB)


def read_gray_png(path: Path) -> np.ndarray:
    data = np.fromfile(str(path), dtype=np.uint8)
    gray = cv2.imdecode(data, cv2.IMREAD_GRAYSCALE)
    if gray is None:
        raise FileNotFoundError(f"Cannot read grayscale image: {path}")
    return gray


def save_gray_png(path: Path, image: np.ndarray) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    if image.ndim != 2 or image.dtype != np.uint8:
        raise ValueError("gray PNG must be uint8 HxW")
    ok, encoded = cv2.imencode(".png", image, [cv2.IMWRITE_PNG_COMPRESSION, 3])
    if not ok:
        raise IOError(f"cv2.imencode failed: {path}")
    path.write_bytes(encoded.tobytes())


def intermediate_paths(base_dir: Path, image_id: str) -> dict[str, Path]:
    return {
        "aligned_rgb": base_dir / "aligned_rgb" / f"{image_id}.png",
        "parsing_label": base_dir / "parsing_label" / f"{image_id}.png",
        "selected_semantic_mask": base_dir
        / "selected_semantic_mask"
        / f"{image_id}.png",
        "final_face_mask": base_dir / "final_face_mask" / f"{image_id}.png",
    }


def landmarks_to_points(
    landmarks: Sequence[Any] | None,
    width: int,
    height: int,
) -> np.ndarray | None:
    if landmarks is None:
        return None
    points = np.array(
        [[lm.x * width, lm.y * height] for lm in landmarks],
        dtype=np.float32,
    )
    if points.ndim != 2 or points.shape[0] < 468 or points.shape[1] != 2:
        return None
    if not np.isfinite(points).all():
        return None
    return points


def load_intermediates(
    image_id: str,
    global_intermediate_dir: Path | None,
    face_mesh: Any,
) -> GlobalIntermediates | None:
    if global_intermediate_dir is None:
        return None
    paths = intermediate_paths(global_intermediate_dir, image_id)
    if not all(path.is_file() for path in paths.values()):
        return None
    aligned_rgb = read_rgb_png(paths["aligned_rgb"])
    label_map = read_gray_png(paths["parsing_label"])
    selected_mask = read_gray_png(paths["selected_semantic_mask"])
    final_mask = read_gray_png(paths["final_face_mask"])
    if aligned_rgb.shape[:2] != label_map.shape:
        raise ValueError(f"Intermediate shape mismatch for ID={image_id}")
    landmarks = landmarks_to_points(
        alignment.run_facemesh(aligned_rgb, face_mesh),
        aligned_rgb.shape[1],
        aligned_rgb.shape[0],
    )
    return GlobalIntermediates(
        original_rgb=None,
        aligned_rgb=aligned_rgb,
        label_map=label_map.astype(np.uint8),
        selected_semantic_mask=(selected_mask > 0).astype(np.uint8) * 255,
        final_face_mask=(final_mask > 0).astype(np.uint8) * 255,
        aligned_landmarks=landmarks,
        source="global_intermediate_dir",
    )


def find_image_for_id(image_id: str, image_dir: Path) -> Path | None:
    for extension in VALID_IMAGE_EXTENSIONS:
        candidate = image_dir / f"{image_id}{extension}"
        if candidate.is_file():
            return candidate
    if image_dir.is_dir():
        image_id_lower = image_id.lower()
        valid = {extension.lower() for extension in VALID_IMAGE_EXTENSIONS}
        for candidate in image_dir.iterdir():
            if (
                candidate.is_file()
                and candidate.suffix.lower() in valid
                and candidate.stem.lower() == image_id_lower
            ):
                return candidate
    return None


def generate_intermediates(
    image_id: str,
    image_dir: Path,
    detector: Any,
    face_mesh: Any,
    parsing_model: torch.nn.Module,
    parsing_device: torch.device,
    args: argparse.Namespace,
) -> GlobalIntermediates:
    input_path = find_image_for_id(image_id, image_dir)
    if input_path is None:
        raise alignment.SampleFailure("failed_no_image", "cannot_find_image_by_ID")
    image_rgb = alignment.read_image_rgb(input_path)
    if image_rgb is None:
        raise alignment.SampleFailure("failed_read_image", "cannot_decode_image")

    detections = alignment.detect_faces(image_rgb, detector)
    selected_face = alignment.select_face(detections, image_rgb.shape)
    if selected_face is None:
        raise alignment.SampleFailure(
            "failed_no_face", "mediapipe_face_detection_returned_none"
        )

    aligned_rgb, _, align_stats, _ = (
        global_hybrid.estimate_original_coordinate_alignment(
            image_rgb, selected_face, face_mesh, int(args.image_size)
        )
    )
    label_map = parsing.run_face_parsing(aligned_rgb, parsing_model, parsing_device)
    selected_mask = parsing.build_selected_semantic_mask(label_map)
    semantic_mask = global_hybrid.build_semantic_regularized_mask(selected_mask)
    candidate_envelope, _ = parsing.build_regularized_face_envelope_mask(
        semantic_mask,
        label_map,
        float(args.forehead_expand_ratio),
        float(args.side_expand_ratio),
        float(args.chin_expand_ratio),
    )
    _, hair_candidate_ratio = global_hybrid._ratio_inside_mask(
        label_map, candidate_envelope, (parsing.CLASS_HAIR,)
    )
    jaggedness = global_hybrid.compute_forehead_top_jaggedness(
        semantic_mask, float(args.forehead_band_ratio)
    )
    final_mask, repair_applied, repair_reason = global_hybrid.build_final_mask(
        semantic_mask,
        candidate_envelope,
        str(args.final_mask_mode),
        float(args.forehead_band_ratio),
        hair_candidate_ratio,
        float(args.hair_repair_threshold),
        jaggedness,
        float(args.jaggedness_threshold),
        bool(args.enable_jaggedness_trigger),
    )
    final_pixels = int((final_mask > 0).sum())
    if final_pixels < max(64, int(round(final_mask.size * 0.01))):
        raise alignment.SampleFailure(
            "failed_empty_selected_mask", "final_mask_too_small"
        )
    landmarks = landmarks_to_points(
        alignment.run_facemesh(aligned_rgb, face_mesh),
        aligned_rgb.shape[1],
        aligned_rgb.shape[0],
    )
    global_metrics = {
        **align_stats,
        "num_faces_detected": len(detections),
        "selected_face_index": selected_face.index,
        "selected_semantic_area_ratio": float((selected_mask > 0).sum())
        / float(selected_mask.size),
        "final_face_mask_area_ratio": final_pixels / float(final_mask.size),
        "forehead_repair_applied": bool(repair_applied),
        "forehead_repair_reason": repair_reason,
        "hair_inside_candidate_envelope_ratio": hair_candidate_ratio,
        "forehead_top_jaggedness": jaggedness,
    }
    return GlobalIntermediates(
        original_rgb=image_rgb,
        aligned_rgb=aligned_rgb,
        label_map=label_map.astype(np.uint8),
        selected_semantic_mask=(selected_mask > 0).astype(np.uint8) * 255,
        final_face_mask=(final_mask > 0).astype(np.uint8) * 255,
        aligned_landmarks=landmarks,
        source="regenerated",
        input_path=str(input_path),
        global_metrics=global_metrics,
    )


def save_intermediates(
    image_id: str,
    intermediates: GlobalIntermediates,
    base_dir: Path,
) -> None:
    paths = intermediate_paths(base_dir, image_id)
    alignment.save_png(paths["aligned_rgb"], intermediates.aligned_rgb)
    save_gray_png(paths["parsing_label"], intermediates.label_map)
    save_gray_png(paths["selected_semantic_mask"], intermediates.selected_semantic_mask)
    save_gray_png(paths["final_face_mask"], intermediates.final_face_mask)


def bbox_from_mask(mask: np.ndarray, min_pixels: int = 1) -> BBox:
    ys, xs = np.where(mask > 0)
    if len(xs) < min_pixels:
        raise RoiFailure(f"mask_has_too_few_pixels:{len(xs)}")
    return BBox(int(xs.min()), int(ys.min()), int(xs.max()) + 1, int(ys.max()) + 1)


def bbox_from_classes(
    label_map: np.ndarray,
    classes: Iterable[int],
    min_pixels: int = 1,
) -> BBox:
    return bbox_from_mask(np.isin(label_map, tuple(classes)), min_pixels=min_pixels)


def bbox_from_landmarks(
    landmarks: np.ndarray | None,
    indices: Sequence[int],
    image_size: int,
) -> BBox | None:
    if landmarks is None:
        return None
    if max(indices) >= len(landmarks):
        return None
    pts = landmarks[np.asarray(indices, dtype=np.int32)]
    pts = np.clip(pts, 0, image_size - 1)
    return BBox(
        int(math.floor(float(pts[:, 0].min()))),
        int(math.floor(float(pts[:, 1].min()))),
        int(math.ceil(float(pts[:, 0].max()))) + 1,
        int(math.ceil(float(pts[:, 1].max()))) + 1,
    )


def clip_bbox(bbox: BBox, image_size: int) -> BBox:
    return BBox(
        max(0, min(image_size, int(bbox.x1))),
        max(0, min(image_size, int(bbox.y1))),
        max(0, min(image_size, int(bbox.x2))),
        max(0, min(image_size, int(bbox.y2))),
    )


def expand_bbox(
    bbox: BBox,
    image_size: int,
    expand_x: float,
    expand_y: float,
) -> BBox:
    cx = (bbox.x1 + bbox.x2) / 2.0
    cy = (bbox.y1 + bbox.y2) / 2.0
    w = bbox.w * (1.0 + 2.0 * expand_x)
    h = bbox.h * (1.0 + 2.0 * expand_y)
    return clip_bbox(
        BBox(
            int(math.floor(cx - w / 2.0)),
            int(math.floor(cy - h / 2.0)),
            int(math.ceil(cx + w / 2.0)),
            int(math.ceil(cy + h / 2.0)),
        ),
        image_size,
    )


def union_bboxes(bboxes: Sequence[BBox | None], image_size: int) -> BBox:
    valid = [bbox for bbox in bboxes if bbox is not None and bbox.area > 0]
    if not valid:
        raise RoiFailure("no_valid_bbox_evidence")
    return clip_bbox(
        BBox(
            min(bbox.x1 for bbox in valid),
            min(bbox.y1 for bbox in valid),
            max(bbox.x2 for bbox in valid),
            max(bbox.y2 for bbox in valid),
        ),
        image_size,
    )


def ensure_bbox_size(bbox: BBox, image_size: int, min_w: int, min_h: int) -> BBox:
    cx = (bbox.x1 + bbox.x2) / 2.0
    cy = (bbox.y1 + bbox.y2) / 2.0
    w = max(float(bbox.w), float(min_w))
    h = max(float(bbox.h), float(min_h))
    return clip_bbox(
        BBox(
            int(math.floor(cx - w / 2.0)),
            int(math.floor(cy - h / 2.0)),
            int(math.ceil(cx + w / 2.0)),
            int(math.ceil(cy + h / 2.0)),
        ),
        image_size,
    )


def validate_bbox(bbox: BBox, roi_type: str, min_w: int, min_h: int) -> None:
    if bbox.w < min_w or bbox.h < min_h:
        raise RoiFailure(f"{roi_type}_bbox_too_small:{bbox}")
    if bbox.area <= 0:
        raise RoiFailure(f"{roi_type}_bbox_empty:{bbox}")


def define_eye_roi(
    label_map: np.ndarray,
    final_mask: np.ndarray,
    landmarks: np.ndarray | None,
    args: argparse.Namespace,
) -> BBox:
    image_size = label_map.shape[0]
    face_bbox = bbox_from_mask(final_mask, min_pixels=64)
    try:
        eye_bbox = bbox_from_classes(
            label_map,
            (
                parsing.CLASS_LEFT_EYE,
                parsing.CLASS_RIGHT_EYE,
            ),
            min_pixels=4,
        )
    except RoiFailure:
        eye_bbox = None
    landmark_bbox = bbox_from_landmarks(landmarks, EYE_INDICES, image_size)
    evidence = union_bboxes((eye_bbox, landmark_bbox), image_size)
    brow_bbox = None
    try:
        brow_bbox = bbox_from_classes(
            label_map,
            (parsing.CLASS_LEFT_BROW, parsing.CLASS_RIGHT_BROW),
            min_pixels=2,
        )
    except RoiFailure:
        brow_bbox = bbox_from_landmarks(landmarks, BROW_INDICES, image_size)
    nose_bbox = None
    try:
        nose_bbox = bbox_from_classes(label_map, (parsing.CLASS_NOSE,), min_pixels=4)
    except RoiFailure:
        nose_bbox = None
    face_w = max(1, face_bbox.w)
    face_h = max(1, face_bbox.h)
    x1 = evidence.x1 - int(round(0.09 * face_w))
    x2 = evidence.x2 + int(round(0.09 * face_w))
    y1 = evidence.y1 - int(round(0.045 * face_h))
    if brow_bbox is not None:
        brow_floor = brow_bbox.y1 + int(round(0.35 * max(1, brow_bbox.h)))
        brow_lower = brow_bbox.y2 - int(round(0.005 * face_h))
        y1 = max(min(y1, brow_lower), brow_floor)
    y2 = evidence.y2 + int(round(0.07 * face_h))
    nose_limit = None
    if nose_bbox is not None:
        nose_limit = nose_bbox.y1 - int(round(0.005 * face_h))
        if nose_limit > evidence.y2 + int(round(0.08 * face_h)):
            y2 = min(y2, nose_limit)
        else:
            nose_limit = None
    min_h = max(int(args.min_roi_height), int(round(0.16 * face_h)))
    max_h = int(round(0.30 * face_h))
    center_y = (evidence.y1 + evidence.y2) / 2.0 + 0.025 * face_h
    if y2 - y1 < min_h:
        # Expand mainly upward. Expanding downward reintroduces nose bridge/tip
        # pixels, which the Final5 eye ROI explicitly avoids.
        y1 = y2 - min_h
    if y2 - y1 > max_h:
        y1 = int(round(center_y - 0.45 * max_h))
        y2 = int(round(center_y + 0.55 * max_h))
        if nose_limit is not None and y2 > nose_limit:
            shift = y2 - nose_limit
            y1 -= shift
            y2 -= shift
    bbox = clip_bbox(BBox(x1, y1, x2, y2), image_size)
    return ensure_bbox_size(bbox, image_size, args.min_roi_width, min_h)


def define_lip_roi(
    label_map: np.ndarray,
    landmarks: np.ndarray | None,
    args: argparse.Namespace,
) -> BBox:
    image_size = label_map.shape[0]
    semantic_bbox = bbox_from_classes(
        label_map,
        (
            parsing.CLASS_MOUTH,
            parsing.CLASS_UPPER_LIP,
            parsing.CLASS_LOWER_LIP,
        ),
        min_pixels=4,
    )
    landmark_bbox = bbox_from_landmarks(landmarks, LIP_INDICES, image_size)
    bbox = union_bboxes((semantic_bbox, landmark_bbox), image_size)
    bbox = expand_bbox(bbox, image_size, expand_x=0.35, expand_y=0.60)
    return ensure_bbox_size(bbox, image_size, args.min_roi_width, args.min_roi_height)


def define_cheek_pair_bboxes(
    label_map: np.ndarray,
    final_mask: np.ndarray,
    landmarks: np.ndarray | None,
    args: argparse.Namespace,
) -> tuple[BBox, BBox, BBox]:
    image_size = label_map.shape[0]
    face_bbox = bbox_from_mask(final_mask, min_pixels=64)
    face_w = max(1, face_bbox.w)
    face_h = max(1, face_bbox.h)
    try:
        eye_bbox = bbox_from_classes(
            label_map,
            (
                parsing.CLASS_LEFT_EYE,
                parsing.CLASS_RIGHT_EYE,
                parsing.CLASS_LEFT_BROW,
                parsing.CLASS_RIGHT_BROW,
            ),
            min_pixels=4,
        )
    except RoiFailure:
        eye_bbox = bbox_from_landmarks(landmarks, EYE_INDICES + BROW_INDICES, image_size)
    lip_bbox = bbox_from_classes(
        label_map,
        (
            parsing.CLASS_MOUTH,
            parsing.CLASS_UPPER_LIP,
            parsing.CLASS_LOWER_LIP,
        ),
        min_pixels=4,
    )
    y1 = eye_bbox.y2 + int(round(0.04 * face_h))
    y2 = lip_bbox.y1 - int(round(0.02 * face_h))
    fallback_y1 = face_bbox.y1 + int(round(0.35 * face_h))
    fallback_y2 = face_bbox.y1 + int(round(0.70 * face_h))
    y1 = max(y1, fallback_y1)
    if y2 <= y1:
        y2 = fallback_y2
    else:
        y2 = min(y2, fallback_y2)

    # Final5 previous cheek ROI: stable face-width proportions in aligned
    # 224-space. Left/right crops are internal only.
    left_x1 = face_bbox.x1 + int(round(0.08 * face_w))
    left_x2 = face_bbox.x1 + int(round(0.37 * face_w))
    right_x1 = face_bbox.x1 + int(round(0.63 * face_w))
    right_x2 = face_bbox.x1 + int(round(0.92 * face_w))

    min_side_w = max(args.min_roi_width, int(round(0.26 * face_w)))
    min_h = max(args.min_roi_height, int(round(0.22 * face_h)))

    left = ensure_bbox_size(
        clip_bbox(BBox(left_x1, y1, left_x2, y2), image_size),
        image_size,
        min_side_w,
        min_h,
    )
    right = ensure_bbox_size(
        clip_bbox(BBox(right_x1, y1, right_x2, y2), image_size),
        image_size,
        min_side_w,
        min_h,
    )
    validate_bbox(left, "left_cheek_internal", args.min_roi_width, args.min_roi_height)
    validate_bbox(right, "right_cheek_internal", args.min_roi_width, args.min_roi_height)
    union = union_bboxes((left, right), image_size)
    return left, right, union


def define_forehead_roi(
    label_map: np.ndarray,
    final_mask: np.ndarray,
    landmarks: np.ndarray | None,
    args: argparse.Namespace,
) -> BBox:
    image_size = label_map.shape[0]
    face_bbox = bbox_from_mask(final_mask, min_pixels=64)
    skin_bbox = bbox_from_classes(label_map, (parsing.CLASS_SKIN,), min_pixels=16)
    brow_bbox = union_bboxes(
        (
            bbox_from_classes(
                label_map,
                (parsing.CLASS_LEFT_BROW, parsing.CLASS_RIGHT_BROW),
                min_pixels=2,
            ),
            bbox_from_landmarks(landmarks, BROW_INDICES, image_size),
        ),
        image_size,
    )
    face_h = max(1, face_bbox.h)
    x1 = brow_bbox.x1 - int(round(0.13 * face_bbox.w))
    x2 = brow_bbox.x2 + int(round(0.13 * face_bbox.w))
    y2 = brow_bbox.y1 - int(round(0.015 * face_h))
    y1 = max(face_bbox.y1, skin_bbox.y1) + int(round(0.01 * face_h))
    min_h = int(round(0.15 * face_h))
    if y2 - y1 < min_h:
        y1 = max(face_bbox.y1, y2 - min_h)
    bbox = clip_bbox(BBox(x1, y1, x2, y2), image_size)
    return ensure_bbox_size(
        bbox,
        image_size,
        args.min_roi_width,
        max(args.min_roi_height, min_h),
    )


def define_chin_roi(
    label_map: np.ndarray,
    final_mask: np.ndarray,
    landmarks: np.ndarray | None,
    args: argparse.Namespace,
) -> BBox:
    image_size = label_map.shape[0]
    face_bbox = bbox_from_mask(final_mask, min_pixels=64)
    face_w = max(1, face_bbox.w)
    face_h = max(1, face_bbox.h)
    mouth_lip_bbox = union_bboxes(
        (
            bbox_from_classes(
                label_map,
                (
                    parsing.CLASS_MOUTH,
                    parsing.CLASS_UPPER_LIP,
                    parsing.CLASS_LOWER_LIP,
                ),
                min_pixels=4,
            ),
            bbox_from_landmarks(landmarks, LIP_INDICES, image_size),
        ),
        image_size,
    )
    skin_bbox = bbox_from_classes(label_map, (parsing.CLASS_SKIN,), min_pixels=16)
    x1 = face_bbox.x1 + int(round(0.20 * face_w))
    x2 = face_bbox.x2 - int(round(0.20 * face_w))
    y1 = mouth_lip_bbox.y2 + int(round(0.02 * face_h))
    y2 = min(
        face_bbox.y2 - int(round(0.02 * face_h)),
        skin_bbox.y2 + int(round(0.02 * face_h)),
    )
    min_h = max(args.min_roi_height, int(round(0.08 * face_h)))
    for classes in ((parsing.CLASS_NECK,), (parsing.CLASS_CLOTH,)):
        try:
            contam_bbox = bbox_from_classes(label_map, classes, min_pixels=4)
        except RoiFailure:
            continue
        contam_limit = contam_bbox.y1 - int(round(0.02 * face_h))
        if contam_limit >= y1 + int(args.min_roi_height):
            y2 = min(y2, contam_limit)
    fallback_y2 = face_bbox.y1 + int(round(0.90 * face_h))
    if y2 <= y1:
        y2 = fallback_y2
    bbox = clip_bbox(BBox(x1, y1, x2, y2), image_size)
    return ensure_bbox_size(
        bbox,
        image_size,
        max(args.min_roi_width, int(round(0.25 * face_w))),
        min_h,
    )


def define_roi_bbox(
    roi_type: str,
    label_map: np.ndarray,
    final_mask: np.ndarray,
    landmarks: np.ndarray | None,
    args: argparse.Namespace,
) -> BBox:
    if roi_type == "eye_roi":
        bbox = define_eye_roi(label_map, final_mask, landmarks, args)
    elif roi_type == "lip_roi":
        bbox = define_lip_roi(label_map, landmarks, args)
    elif roi_type == "cheek_roi":
        _, _, bbox = define_cheek_pair_bboxes(label_map, final_mask, landmarks, args)
    elif roi_type == "forehead_roi":
        bbox = define_forehead_roi(label_map, final_mask, landmarks, args)
    elif roi_type == "chin_roi":
        bbox = define_chin_roi(label_map, final_mask, landmarks, args)
    else:
        raise RoiFailure(f"unsupported_roi_type:{roi_type}")
    validate_bbox(bbox, roi_type, int(args.min_roi_width), int(args.min_roi_height))
    return bbox


def crop_to_canvas(
    image_rgb: np.ndarray,
    bbox: BBox,
    canvas_size: int,
    padding_color: tuple[int, int, int],
    keep_aspect_ratio: bool,
) -> CanvasResult:
    crop = image_rgb[bbox.y1 : bbox.y2, bbox.x1 : bbox.x2]
    if crop.size == 0:
        raise RoiFailure(f"empty_crop:{bbox}")
    if not keep_aspect_ratio:
        resized = cv2.resize(crop, (canvas_size, canvas_size), interpolation=cv2.INTER_AREA)
        return CanvasResult(resized, canvas_size, canvas_size, 0, 0, 0, 0)
    scale = min(canvas_size / float(crop.shape[1]), canvas_size / float(crop.shape[0]))
    content_w = max(1, int(round(crop.shape[1] * scale)))
    content_h = max(1, int(round(crop.shape[0] * scale)))
    resized = cv2.resize(crop, (content_w, content_h), interpolation=cv2.INTER_AREA)
    canvas = np.zeros((canvas_size, canvas_size, 3), dtype=np.uint8)
    canvas[:, :] = np.array(padding_color, dtype=np.uint8)
    pad_left = (canvas_size - content_w) // 2
    pad_top = (canvas_size - content_h) // 2
    pad_right = canvas_size - content_w - pad_left
    pad_bottom = canvas_size - content_h - pad_top
    canvas[pad_top : pad_top + content_h, pad_left : pad_left + content_w] = resized
    return CanvasResult(
        image=canvas,
        content_w=content_w,
        content_h=content_h,
        padding_top=pad_top,
        padding_bottom=pad_bottom,
        padding_left=pad_left,
        padding_right=pad_right,
    )


def crop_to_canvas_size(
    image_rgb: np.ndarray,
    bbox: BBox,
    canvas_width: int,
    canvas_height: int,
    padding_color: tuple[int, int, int],
    keep_aspect_ratio: bool,
) -> CanvasResult:
    crop = image_rgb[bbox.y1 : bbox.y2, bbox.x1 : bbox.x2]
    if crop.size == 0:
        raise RoiFailure(f"empty_crop:{bbox}")
    if not keep_aspect_ratio:
        resized = cv2.resize(crop, (canvas_width, canvas_height), interpolation=cv2.INTER_AREA)
        return CanvasResult(resized, canvas_width, canvas_height, 0, 0, 0, 0)
    scale = min(canvas_width / float(crop.shape[1]), canvas_height / float(crop.shape[0]))
    content_w = max(1, int(round(crop.shape[1] * scale)))
    content_h = max(1, int(round(crop.shape[0] * scale)))
    resized = cv2.resize(crop, (content_w, content_h), interpolation=cv2.INTER_AREA)
    canvas = np.zeros((canvas_height, canvas_width, 3), dtype=np.uint8)
    canvas[:, :] = np.array(padding_color, dtype=np.uint8)
    pad_left = (canvas_width - content_w) // 2
    pad_top = (canvas_height - content_h) // 2
    pad_right = canvas_width - content_w - pad_left
    pad_bottom = canvas_height - content_h - pad_top
    canvas[pad_top : pad_top + content_h, pad_left : pad_left + content_w] = resized
    return CanvasResult(
        image=canvas,
        content_w=content_w,
        content_h=content_h,
        padding_top=pad_top,
        padding_bottom=pad_bottom,
        padding_left=pad_left,
        padding_right=pad_right,
    )


def crop_cheek_pair_to_canvas(
    image_rgb: np.ndarray,
    left_bbox: BBox,
    right_bbox: BBox,
    canvas_size: int,
    padding_color: tuple[int, int, int],
    keep_aspect_ratio: bool,
) -> CanvasResult:
    _ = keep_aspect_ratio
    half_width = canvas_size // 2
    right_width = canvas_size - half_width
    left = crop_to_canvas_size(
        image_rgb, left_bbox, half_width, canvas_size, padding_color, False
    )
    right = crop_to_canvas_size(
        image_rgb, right_bbox, right_width, canvas_size, padding_color, False
    )
    image = np.concatenate([left.image, right.image], axis=1)
    return CanvasResult(
        image=image,
        content_w=left.content_w + right.content_w,
        content_h=max(left.content_h, right.content_h),
        padding_top=max(left.padding_top, right.padding_top),
        padding_bottom=max(left.padding_bottom, right.padding_bottom),
        padding_left=left.padding_left,
        padding_right=right.padding_right,
    )


def roi_target_mask(
    roi_type: str,
    label_map: np.ndarray,
    final_mask: np.ndarray,
) -> np.ndarray:
    _ = roi_type, label_map
    # v2 masked ROI is deliberately the raw ROI intersected with the global
    # final face mask only. Parsing labels are used for QC/statistics and ROI
    # validity checks, not for carving ROI-specific internal semantic holes.
    mask = final_mask > 0
    if int(mask.sum()) == 0:
        raise RoiFailure("global_final_face_mask_empty")
    return mask.astype(np.uint8) * 255


def validate_required_semantics(
    roi_type: str,
    label_map: np.ndarray,
    bbox: BBox,
) -> None:
    required_classes = ROI_REQUIRED_CLASSES.get(roi_type, ())
    if not required_classes:
        return
    region = label_map[bbox.y1 : bbox.y2, bbox.x1 : bbox.x2]
    required_pixels = int(np.isin(region, required_classes).sum())
    min_pixels = max(3, int(round(region.size * 0.001)))
    if required_pixels < min_pixels:
        raise RoiFailure(
            f"{roi_type}_required_semantic_missing:"
            f"pixels={required_pixels},threshold={min_pixels}"
        )


def semantic_ratios(label_map: np.ndarray, bbox: BBox) -> dict[str, float]:
    region = label_map[bbox.y1 : bbox.y2, bbox.x1 : bbox.x2]
    return semantic_ratios_from_regions([region])


def semantic_ratios_from_regions(regions: Sequence[np.ndarray]) -> dict[str, float]:
    flattened = [
        region.reshape(-1)
        for region in regions
        if region.size > 0
    ]
    if flattened:
        region = np.concatenate(flattened)
    else:
        region = np.empty((0,), dtype=np.uint8)
    denominator = float(max(1, region.size))

    def ratio(classes: Iterable[int]) -> float:
        return float(np.isin(region, tuple(classes)).sum()) / denominator

    return {
        "skin_ratio": ratio((parsing.CLASS_SKIN,)),
        "hair_ratio": ratio((parsing.CLASS_HAIR,)),
        "background_ratio": ratio((parsing.CLASS_BACKGROUND,)),
        "neck_ratio": ratio((parsing.CLASS_NECK,)),
        "cloth_ratio": ratio((parsing.CLASS_CLOTH,)),
        "ear_ratio": ratio((parsing.CLASS_LEFT_EAR, parsing.CLASS_RIGHT_EAR)),
        "eye_ratio": ratio((parsing.CLASS_LEFT_EYE, parsing.CLASS_RIGHT_EYE)),
        "brow_ratio": ratio((parsing.CLASS_LEFT_BROW, parsing.CLASS_RIGHT_BROW)),
        "nose_ratio": ratio((parsing.CLASS_NOSE,)),
        "mouth_ratio": ratio((parsing.CLASS_MOUTH,)),
        "lip_ratio": ratio((parsing.CLASS_UPPER_LIP, parsing.CLASS_LOWER_LIP)),
    }


def mask_ratio_from_regions(mask: np.ndarray, bboxes: Sequence[BBox]) -> float:
    regions = [
        mask[bbox.y1 : bbox.y2, bbox.x1 : bbox.x2] > 0
        for bbox in bboxes
    ]
    area = sum(int(region.size) for region in regions)
    foreground = sum(int(region.sum()) for region in regions)
    return float(foreground) / float(max(1, area))


def warning_flags(
    roi_type: str,
    metrics: dict[str, Any],
    args: argparse.Namespace,
) -> list[str]:
    warnings: list[str] = []
    if metrics["padding_ratio"] > float(args.max_padding_ratio):
        warnings.append("warning_high_padding_ratio")
    if metrics["background_ratio"] > float(args.max_background_ratio):
        warnings.append("warning_high_background_ratio")
    if metrics["cloth_ratio"] > float(args.max_cloth_ratio):
        warnings.append("warning_cloth_contamination")
    if metrics["neck_ratio"] > float(args.max_neck_ratio):
        warnings.append("warning_neck_contamination")
    if metrics["skin_ratio"] < 0.05:
        warnings.append("warning_low_skin_ratio")
    if roi_type == "forehead_roi":
        if metrics["hair_ratio"] > float(args.forehead_hair_warning):
            warnings.append("warning_forehead_hair_occlusion")
        if metrics["background_ratio"] > float(args.max_background_ratio):
            warnings.append("warning_forehead_background_contamination")
        if metrics["skin_ratio"] < 0.20:
            warnings.append("warning_forehead_low_skin_ratio")
        if metrics["bbox_h"] < 24:
            warnings.append("warning_forehead_too_small")
    if roi_type == "eye_roi":
        if metrics["eye_ratio"] < 0.005:
            warnings.append("warning_eye_missed")
        if metrics["bbox_h"] < 24:
            warnings.append("warning_eye_too_narrow")
        if metrics["nose_ratio"] > float(args.eye_nose_warning):
            warnings.append("warning_eye_contains_nose")
        if metrics["nose_ratio"] > float(args.eye_nose_warning) * 0.5:
            warnings.append("warning_eye_too_low")
        if metrics["brow_ratio"] > 0.20:
            warnings.append("warning_eye_too_high")
    if roi_type == "lip_roi" and metrics["mouth_ratio"] + metrics["lip_ratio"] < 0.01:
        warnings.append("warning_lip_missed")
    if roi_type == "lip_roi" and metrics["mouth_ratio"] + metrics["lip_ratio"] < 0.04:
        warnings.append("warning_low_mouth_lip_ratio")
    if roi_type == "lip_roi" and (metrics["neck_ratio"] + metrics["cloth_ratio"]) > 0.05:
        warnings.append("warning_lip_contains_neck_or_cloth")
    if roi_type == "lip_roi" and metrics["bbox_h"] < 20:
        warnings.append("warning_lip_too_small")
    if roi_type == "cheek_roi":
        if metrics["skin_ratio"] < 0.20:
            warnings.append("warning_cheek_low_skin_ratio")
        if metrics["background_ratio"] > float(args.cheek_background_warning):
            warnings.append("warning_cheek_background_contamination")
        if metrics["mouth_ratio"] + metrics["lip_ratio"] > 0.08:
            warnings.append("warning_cheek_contains_mouth")
        if metrics["eye_ratio"] > 0.02:
            warnings.append("warning_cheek_contains_eye")
        if metrics.get("cheek_min_side_w", metrics["bbox_w"]) < 40:
            warnings.append("warning_cheek_too_narrow")
        if metrics.get("cheek_pair_asymmetry", 0.0) > 0.30:
            warnings.append("warning_cheek_pair_asymmetry")
    if roi_type == "chin_roi":
        if metrics["mouth_ratio"] + metrics["lip_ratio"] > 0.08:
            warnings.append("warning_chin_contains_mouth")
        if metrics["neck_ratio"] > float(args.chin_neck_warning):
            warnings.append("warning_chin_contains_neck")
        if metrics["cloth_ratio"] > float(args.chin_cloth_warning):
            warnings.append("warning_chin_contains_cloth")
        if metrics["skin_ratio"] < 0.20:
            warnings.append("warning_chin_low_skin_ratio")
        if metrics["bbox_h"] < 20:
            warnings.append("warning_chin_too_small")
        if metrics["background_ratio"] > float(args.max_background_ratio):
            warnings.append("warning_chin_high_background_ratio")
    return warnings


def make_masked_full_image(
    aligned_rgb: np.ndarray,
    target_mask: np.ndarray,
) -> np.ndarray:
    masked = aligned_rgb.copy()
    masked[target_mask == 0] = 0
    return masked


def draw_mask_overlay(image_rgb: np.ndarray, mask: np.ndarray, color: tuple[int, int, int]) -> np.ndarray:
    overlay = image_rgb.copy()
    foreground = mask > 0
    overlay[foreground] = (
        0.60 * overlay[foreground].astype(np.float32)
        + 0.40 * np.array(color, dtype=np.float32)
    ).astype(np.uint8)
    return overlay


def draw_roi_bboxes(image_rgb: np.ndarray, boxes: dict[str, BBox | None]) -> np.ndarray:
    canvas = image_rgb.copy()
    colors = {
        "eye_roi": (255, 220, 0),
        "lip_roi": (255, 60, 60),
        "cheek_roi": (80, 220, 80),
        "left_cheek_internal": (80, 220, 80),
        "right_cheek_internal": (80, 220, 80),
        "forehead_roi": (80, 160, 255),
        "chin_roi": (220, 80, 255),
    }
    for roi_type, bbox in boxes.items():
        if bbox is None:
            continue
        color = colors.get(roi_type, (255, 255, 255))
        cv2.rectangle(
            canvas,
            (bbox.x1, bbox.y1),
            (max(bbox.x1, bbox.x2 - 1), max(bbox.y1, bbox.y2 - 1)),
            color,
            2,
        )
        cv2.putText(
            canvas,
            roi_type.replace("_roi", ""),
            (bbox.x1, max(12, bbox.y1 - 4)),
            cv2.FONT_HERSHEY_SIMPLEX,
            0.42,
            color,
            1,
            cv2.LINE_AA,
        )
    return canvas


def fit_panel(image: np.ndarray | None, title: str, size: tuple[int, int] = (224, 224)) -> np.ndarray:
    width, height = size
    panel = np.zeros((height, width, 3), dtype=np.uint8)
    if image is not None:
        if image.ndim == 2:
            image = cv2.cvtColor(image, cv2.COLOR_GRAY2RGB)
        scale = min(width / image.shape[1], height / image.shape[0])
        new_w = max(1, int(round(image.shape[1] * scale)))
        new_h = max(1, int(round(image.shape[0] * scale)))
        resized = cv2.resize(image, (new_w, new_h), interpolation=cv2.INTER_AREA)
        x = (width - new_w) // 2
        y = (height - new_h) // 2
        panel[y : y + new_h, x : x + new_w] = resized
    cv2.putText(panel, title[:26], (8, 18), cv2.FONT_HERSHEY_SIMPLEX, 0.45, (255, 255, 255), 1, cv2.LINE_AA)
    return panel


def save_qc_preview(
    output_path: Path,
    image_id: str,
    status_text: str,
    original_rgb: np.ndarray | None,
    aligned_rgb: np.ndarray | None,
    label_map: np.ndarray | None,
    final_mask: np.ndarray | None,
    bboxes: dict[str, BBox | None],
    raw_images: dict[str, np.ndarray],
    masked_images: dict[str, np.ndarray],
) -> None:
    panels: list[np.ndarray] = []
    parsing_map = parsing.colorize_parsing_label_map(label_map) if label_map is not None else None
    mask_overlay = (
        draw_mask_overlay(aligned_rgb, final_mask, (255, 90, 40))
        if aligned_rgb is not None and final_mask is not None
        else None
    )
    bbox_overlay = draw_roi_bboxes(aligned_rgb, bboxes) if aligned_rgb is not None else None
    panels.extend(
        [
            fit_panel(original_rgb, f"{image_id} original"),
            fit_panel(aligned_rgb, f"{image_id} aligned"),
            fit_panel(parsing_map, "parsing label"),
            fit_panel(mask_overlay, "global final mask"),
            fit_panel(bbox_overlay, "ROI bbox overlay"),
        ]
    )
    for roi_type in DEFAULT_ROI_TYPES:
        panels.append(fit_panel(raw_images.get(roi_type), f"raw {roi_type}"))
    for roi_type in DEFAULT_ROI_TYPES:
        panels.append(fit_panel(masked_images.get(roi_type), f"masked {roi_type}"))
    while len(panels) % 5:
        panels.append(fit_panel(None, ""))
    rows = [np.hstack(panels[i : i + 5]) for i in range(0, len(panels), 5)]
    grid = np.vstack(rows)
    cv2.putText(
        grid,
        status_text[:120],
        (8, grid.shape[0] - 10),
        cv2.FONT_HERSHEY_SIMPLEX,
        0.55,
        (255, 255, 255),
        1,
        cv2.LINE_AA,
    )
    alignment.save_png(output_path, grid)


def base_record(split_row: dict[str, Any]) -> dict[str, Any]:
    return {
        column: split_row.get(column, "")
        for column in PRESERVE_COLUMNS
        if column in split_row
    }


def process_roi(
    split_row: dict[str, Any],
    roi_type: str,
    intermediates: GlobalIntermediates,
    dirs: dict[str, Path],
    args: argparse.Namespace,
    padding_color: tuple[int, int, int],
) -> tuple[dict[str, Any], BBox | None, np.ndarray | None, np.ndarray | None]:
    image_id = str(split_row["ID"])
    record = base_record(split_row)
    record.update(
        {
            "roi_type": roi_type,
            "roi_raw_path": "",
            "roi_masked_path": "",
            "roi_success": False,
            "roi_valid_flag": False,
            "roi_warning_flag": False,
            "failure_reason": "",
        }
    )
    try:
        if roi_type == "cheek_roi":
            left_bbox, right_bbox, bbox = define_cheek_pair_bboxes(
                intermediates.label_map,
                intermediates.final_face_mask,
                intermediates.aligned_landmarks,
                args,
            )
            for side_name, side_bbox in (("left", left_bbox), ("right", right_bbox)):
                side_region = intermediates.label_map[
                    side_bbox.y1 : side_bbox.y2, side_bbox.x1 : side_bbox.x2
                ]
                skin_pixels = int((side_region == parsing.CLASS_SKIN).sum())
                if skin_pixels < max(4, int(round(side_region.size * 0.02))):
                    raise RoiFailure(f"cheek_{side_name}_skin_missing")

            target_mask = roi_target_mask(
                roi_type, intermediates.label_map, intermediates.final_face_mask
            )
            raw_canvas = crop_cheek_pair_to_canvas(
                intermediates.aligned_rgb,
                left_bbox,
                right_bbox,
                int(args.canvas_size),
                padding_color,
                bool(args.keep_aspect_ratio),
            )
            masked_full = make_masked_full_image(intermediates.aligned_rgb, target_mask)
            masked_canvas = crop_cheek_pair_to_canvas(
                masked_full,
                left_bbox,
                right_bbox,
                int(args.canvas_size),
                padding_color,
                bool(args.keep_aspect_ratio),
            )
            raw_path = dirs["roi_raw"] / roi_type / f"{image_id}.png"
            masked_path = dirs["roi_masked"] / roi_type / f"{image_id}.png"
            alignment.save_png(raw_path, raw_canvas.image)
            alignment.save_png(masked_path, masked_canvas.image)

            ratios = semantic_ratios_from_regions(
                [
                    intermediates.label_map[
                        left_bbox.y1 : left_bbox.y2, left_bbox.x1 : left_bbox.x2
                    ],
                    intermediates.label_map[
                        right_bbox.y1 : right_bbox.y2, right_bbox.x1 : right_bbox.x2
                    ],
                ]
            )
            side_mask_ratio = mask_ratio_from_regions(
                intermediates.final_face_mask, (left_bbox, right_bbox)
            )
            metrics = {
                "bbox_x1": bbox.x1,
                "bbox_y1": bbox.y1,
                "bbox_x2": bbox.x2 - 1,
                "bbox_y2": bbox.y2 - 1,
                "bbox_w": bbox.w,
                "bbox_h": bbox.h,
                "left_cheek_bbox_x1": left_bbox.x1,
                "left_cheek_bbox_y1": left_bbox.y1,
                "left_cheek_bbox_x2": left_bbox.x2 - 1,
                "left_cheek_bbox_y2": left_bbox.y2 - 1,
                "right_cheek_bbox_x1": right_bbox.x1,
                "right_cheek_bbox_y1": right_bbox.y1,
                "right_cheek_bbox_x2": right_bbox.x2 - 1,
                "right_cheek_bbox_y2": right_bbox.y2 - 1,
                "cheek_min_side_w": min(left_bbox.w, right_bbox.w),
                "cheek_pair_asymmetry": abs(left_bbox.w - right_bbox.w)
                / float(max(1, max(left_bbox.w, right_bbox.w))),
                "canvas_size": int(args.canvas_size),
                "content_w": raw_canvas.content_w,
                "content_h": raw_canvas.content_h,
                "padding_top": raw_canvas.padding_top,
                "padding_bottom": raw_canvas.padding_bottom,
                "padding_left": raw_canvas.padding_left,
                "padding_right": raw_canvas.padding_right,
                "padding_ratio": raw_canvas.padding_ratio,
                "content_ratio": raw_canvas.content_ratio,
                "roi_resize_mode": "pair_concat_fixed_half",
                "valid_semantic_ratio": side_mask_ratio,
                "target_semantic_ratio": side_mask_ratio,
                **ratios,
            }
            flags = warning_flags(roi_type, metrics, args)
            record.update(
                {
                    "roi_raw_path": str(raw_path),
                    "roi_masked_path": str(masked_path),
                    "roi_success": True,
                    "roi_valid_flag": True,
                    "roi_warning_flag": bool(flags),
                    "warning_list": ";".join(flags),
                    **metrics,
                }
            )
            return record, bbox, raw_canvas.image, masked_canvas.image

        bbox = define_roi_bbox(
            roi_type,
            intermediates.label_map,
            intermediates.final_face_mask,
            intermediates.aligned_landmarks,
            args,
        )
        validate_required_semantics(roi_type, intermediates.label_map, bbox)
        target_mask = roi_target_mask(
            roi_type, intermediates.label_map, intermediates.final_face_mask
        )
        target_region = target_mask[bbox.y1 : bbox.y2, bbox.x1 : bbox.x2]
        target_pixels = int((target_region > 0).sum())
        if target_pixels == 0:
            raise RoiFailure(f"{roi_type}_target_semantic_missing_inside_bbox")

        raw_canvas = crop_to_canvas(
            intermediates.aligned_rgb,
            bbox,
            int(args.canvas_size),
            padding_color,
            bool(args.keep_aspect_ratio),
        )
        masked_full = make_masked_full_image(intermediates.aligned_rgb, target_mask)
        masked_canvas = crop_to_canvas(
            masked_full,
            bbox,
            int(args.canvas_size),
            padding_color,
            bool(args.keep_aspect_ratio),
        )
        raw_path = dirs["roi_raw"] / roi_type / f"{image_id}.png"
        masked_path = dirs["roi_masked"] / roi_type / f"{image_id}.png"
        alignment.save_png(raw_path, raw_canvas.image)
        alignment.save_png(masked_path, masked_canvas.image)

        ratios = semantic_ratios(intermediates.label_map, bbox)
        valid_region = intermediates.final_face_mask[bbox.y1 : bbox.y2, bbox.x1 : bbox.x2] > 0
        metrics = {
            "bbox_x1": bbox.x1,
            "bbox_y1": bbox.y1,
            "bbox_x2": bbox.x2 - 1,
            "bbox_y2": bbox.y2 - 1,
            "bbox_w": bbox.w,
            "bbox_h": bbox.h,
            "canvas_size": int(args.canvas_size),
            "content_w": raw_canvas.content_w,
            "content_h": raw_canvas.content_h,
            "padding_top": raw_canvas.padding_top,
            "padding_bottom": raw_canvas.padding_bottom,
            "padding_left": raw_canvas.padding_left,
            "padding_right": raw_canvas.padding_right,
            "padding_ratio": raw_canvas.padding_ratio,
            "content_ratio": raw_canvas.content_ratio,
            "roi_resize_mode": "keep_aspect_pad_canvas",
            "valid_semantic_ratio": float(valid_region.sum()) / float(max(1, bbox.area)),
            "target_semantic_ratio": target_pixels / float(max(1, bbox.area)),
            **ratios,
        }
        if roi_type == "chin_roi":
            metrics.update(
                {
                    "chin_contains_neck_ratio": metrics["neck_ratio"],
                    "chin_contains_cloth_ratio": metrics["cloth_ratio"],
                    "chin_mouth_lip_ratio": metrics["mouth_ratio"] + metrics["lip_ratio"],
                }
            )
        flags = warning_flags(roi_type, metrics, args)
        record.update(
            {
                "roi_raw_path": str(raw_path),
                "roi_masked_path": str(masked_path),
                "roi_success": True,
                "roi_valid_flag": True,
                "roi_warning_flag": bool(flags),
                "warning_list": ";".join(flags),
                **metrics,
            }
        )
        return record, bbox, raw_canvas.image, masked_canvas.image
    except Exception as exc:
        reason = exc.reason if isinstance(exc, RoiFailure) else f"{type(exc).__name__}: {exc}"
        record["failure_reason"] = reason
        return record, None, None, None


def process_sample(
    split_row: dict[str, Any],
    args: argparse.Namespace,
    dirs: dict[str, Path],
    detector: Any,
    face_mesh: Any,
    parsing_model: torch.nn.Module,
    parsing_device: torch.device,
    padding_color: tuple[int, int, int],
) -> tuple[list[dict[str, Any]], dict[str, Any], dict[str, BBox | None], dict[str, np.ndarray], dict[str, np.ndarray], GlobalIntermediates | None]:
    image_id = str(split_row["ID"])
    roi_records: list[dict[str, Any]] = []
    bboxes: dict[str, BBox | None] = {}
    raw_images: dict[str, np.ndarray] = {}
    masked_images: dict[str, np.ndarray] = {}
    sample = base_record(split_row)
    sample.update(
        {
            "global_success": False,
            "global_intermediate_source": "",
            "global_failure_reason": "",
        }
    )
    try:
        intermediates = load_intermediates(
            image_id, args.global_intermediate_dir, face_mesh
        )
        if intermediates is None:
            intermediates = generate_intermediates(
                image_id,
                args.image_dir,
                detector,
                face_mesh,
                parsing_model,
                parsing_device,
                args,
            )
            if bool(args.save_intermediates):
                save_intermediates(
                    image_id, intermediates, dirs["intermediates_optional"]
                )
        elif intermediates.original_rgb is None:
            original_path = find_image_for_id(image_id, args.image_dir)
            if original_path is not None:
                original_rgb = alignment.read_image_rgb(original_path)
                if original_rgb is not None:
                    intermediates.original_rgb = original_rgb
                    intermediates.input_path = str(original_path)
        sample.update(
            {
                "global_success": True,
                "global_intermediate_source": intermediates.source,
                "input_path": intermediates.input_path,
            }
        )
        if intermediates.global_metrics:
            sample.update(intermediates.global_metrics)
        for roi_type in args.roi_types:
            record, bbox, raw_image, masked_image = process_roi(
                split_row, roi_type, intermediates, dirs, args, padding_color
            )
            roi_records.append(record)
            bboxes[roi_type] = bbox
            if roi_type == "cheek_roi" and bbox is not None and bool(record.get("roi_success", False)):
                try:
                    bboxes["left_cheek_internal"] = BBox(
                        int(record["left_cheek_bbox_x1"]),
                        int(record["left_cheek_bbox_y1"]),
                        int(record["left_cheek_bbox_x2"]) + 1,
                        int(record["left_cheek_bbox_y2"]) + 1,
                    )
                    bboxes["right_cheek_internal"] = BBox(
                        int(record["right_cheek_bbox_x1"]),
                        int(record["right_cheek_bbox_y1"]),
                        int(record["right_cheek_bbox_x2"]) + 1,
                        int(record["right_cheek_bbox_y2"]) + 1,
                    )
                except Exception:
                    pass
            if raw_image is not None:
                raw_images[roi_type] = raw_image
            if masked_image is not None:
                masked_images[roi_type] = masked_image
    except alignment.SampleFailure as exc:
        intermediates = None
        sample["global_failure_reason"] = f"{exc.status}:{exc.reason}"
        for roi_type in args.roi_types:
            record = base_record(split_row)
            record.update(
                {
                    "roi_type": roi_type,
                    "roi_raw_path": "",
                    "roi_masked_path": "",
                    "roi_success": False,
                    "roi_valid_flag": False,
                    "roi_warning_flag": False,
                    "failure_reason": sample["global_failure_reason"],
                }
            )
            roi_records.append(record)
            bboxes[roi_type] = None
    except Exception as exc:
        intermediates = None
        sample["global_failure_reason"] = f"{type(exc).__name__}: {exc}"
        for roi_type in args.roi_types:
            record = base_record(split_row)
            record.update(
                {
                    "roi_type": roi_type,
                    "roi_raw_path": "",
                    "roi_masked_path": "",
                    "roi_success": False,
                    "roi_valid_flag": False,
                    "roi_warning_flag": False,
                    "failure_reason": sample["global_failure_reason"],
                }
            )
            roi_records.append(record)
            bboxes[roi_type] = None
    return roi_records, sample, bboxes, raw_images, masked_images, intermediates


def build_success_matrix(
    split_rows: list[dict[str, Any]],
    roi_df: pd.DataFrame,
    roi_types: Sequence[str],
    core_roi_types: Sequence[str],
) -> pd.DataFrame:
    records: list[dict[str, Any]] = []
    for split_row in split_rows:
        image_id = str(split_row["ID"])
        subset = roi_df[roi_df["ID"].astype(str) == image_id]
        record = base_record(split_row)
        failed: list[str] = []
        warning_rois: list[str] = []
        for roi_type in roi_types:
            rows = subset[subset["roi_type"] == roi_type]
            success = bool(len(rows) and bool(rows.iloc[0]["roi_success"]))
            record[f"{roi_type}_success"] = success
            if success:
                record[f"{roi_type}_raw_path"] = str(rows.iloc[0].get("roi_raw_path", ""))
                record[f"{roi_type}_masked_path"] = str(rows.iloc[0].get("roi_masked_path", ""))
                if bool(rows.iloc[0].get("roi_warning_flag", False)):
                    warning_rois.append(roi_type)
            else:
                record[f"{roi_type}_raw_path"] = ""
                record[f"{roi_type}_masked_path"] = ""
                failed.append(roi_type)
        record["core_all_success"] = all(
            bool(record.get(f"{roi_type}_success", False))
            for roi_type in core_roi_types
        )
        record["all_roi_success"] = all(
            bool(record.get(f"{roi_type}_success", False)) for roi_type in roi_types
        )
        record["failed_roi_list"] = ";".join(failed)
        record["warning_roi_list"] = ";".join(warning_rois)
        records.append(record)
    return pd.DataFrame(records)


def build_valid_ids(
    success_matrix: pd.DataFrame,
    roi_types: Sequence[str],
    core_roi_types: Sequence[str],
) -> pd.DataFrame:
    valid = success_matrix[success_matrix["core_all_success"] == True].copy()  # noqa: E712
    columns = [
        column for column in PRESERVE_COLUMNS if column in valid.columns
    ]
    for roi_type in core_roi_types:
        columns.append(f"{roi_type}_raw_path")
    for roi_type in core_roi_types:
        columns.append(f"{roi_type}_masked_path")
    columns = [column for column in columns if column in valid.columns]
    return valid.loc[:, columns].copy()


def summarize(
    split_df: pd.DataFrame,
    roi_df: pd.DataFrame,
    success_matrix: pd.DataFrame,
    sample_df: pd.DataFrame,
    args: argparse.Namespace,
    output_path: Path,
) -> None:
    lines: list[str] = []
    lines.append("Global aligned face parsing Final5 ROI preprocessing summary")
    lines.append("=" * 62)
    lines.append(f"total_samples: {len(split_df)}")
    lines.append(f"output_dir: {args.output_dir}")
    lines.append(f"global_intermediate_dir: {args.global_intermediate_dir}")
    lines.append(f"save_intermediates: {bool(args.save_intermediates)}")
    lines.append(f"roi_types: {','.join(args.roi_types)}")
    lines.append(f"core_roi_types: {','.join(args.core_roi_types)}")
    lines.append("Image output: RGB uint8 PNG; no ImageNet Normalize is saved.")
    lines.append("")
    if "global_success" in sample_df.columns:
        lines.append(f"global_intermediate_success_samples: {int(sample_df['global_success'].sum())}")
    lines.append(f"core_all_success_samples: {int(success_matrix['core_all_success'].sum())}")
    lines.append(f"all_roi_success_samples: {int(success_matrix['all_roi_success'].sum())}")
    lines.append("")
    lines.append("ROI success counts:")
    for roi_type in args.roi_types:
        column = f"{roi_type}_success"
        lines.append(f"  {roi_type}: {int(success_matrix[column].sum())}")
    lines.append("")
    if "fold" in success_matrix.columns:
        lines.append("core_all_success by fold:")
        by_fold = success_matrix.groupby("fold")["core_all_success"].sum()
        for fold, count in by_fold.items():
            lines.append(f"  fold={fold}: {int(count)}")
    if "label" in success_matrix.columns:
        lines.append("core_all_success by label:")
        by_label = success_matrix.groupby("label")["core_all_success"].sum()
        for label, count in by_label.items():
            lines.append(f"  label={label}: {int(count)}")
    if "extreme_label" in success_matrix.columns:
        lines.append("core_all_success by extreme_label:")
        by_label = success_matrix.groupby("extreme_label")["core_all_success"].sum()
        for label, count in by_label.items():
            lines.append(f"  extreme_label={label}: {int(count)}")
    if "SEX" in success_matrix.columns:
        lines.append("core_all_success by SEX:")
        by_sex = success_matrix.groupby("SEX")["core_all_success"].sum()
        for sex, count in by_sex.items():
            lines.append(f"  SEX={sex}: {int(count)}")
    lines.append("")
    lines.append("ROI warning counts:")
    aggregate_warnings: Counter[str] = Counter()
    for roi_type, subset in roi_df.groupby("roi_type", sort=True):
        warnings = Counter()
        for value in subset.get("warning_list", pd.Series(dtype=str)).fillna(""):
            for item in str(value).split(";"):
                if item:
                    warnings[item] += 1
                    aggregate_warnings[item] += 1
        lines.append(f"  {roi_type}: {dict(warnings)}")
    lines.append("Key warning totals:")
    for warning_name in (
        "warning_high_padding_ratio",
        "warning_eye_contains_nose",
        "warning_cheek_contains_eye",
        "warning_cheek_contains_mouth",
        "warning_cheek_background_contamination",
        "warning_cheek_low_skin_ratio",
        "warning_cheek_too_narrow",
        "warning_cheek_pair_asymmetry",
        "warning_chin_contains_neck",
        "warning_chin_contains_cloth",
    ):
        lines.append(f"  {warning_name}: {int(aggregate_warnings[warning_name])}")
    lines.append("")
    lines.append("ROI failure reasons:")
    failures = roi_df[roi_df["roi_success"] == False]  # noqa: E712
    if failures.empty:
        lines.append("  none")
    else:
        counts = failures["failure_reason"].fillna("").value_counts()
        for reason, count in counts.items():
            lines.append(f"  {reason}: {int(count)}")
    output_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def maybe_save_qc(
    image_id: str,
    sample_row: dict[str, Any],
    roi_records: list[dict[str, Any]],
    bboxes: dict[str, BBox | None],
    raw_images: dict[str, np.ndarray],
    masked_images: dict[str, np.ndarray],
    intermediates: GlobalIntermediates | None,
    dirs: dict[str, Path],
    args: argparse.Namespace,
    qc_counts: Counter[str],
    random_success_ids: set[str],
) -> None:
    if intermediates is None:
        if qc_counts["roi_failure"] < args.num_qc_preview:
            save_qc_preview(
                dirs["qc_roi_failure"] / f"{image_id}.png",
                image_id,
                str(sample_row.get("global_failure_reason", "")),
                None,
                None,
                None,
                None,
                bboxes,
                raw_images,
                masked_images,
            )
            qc_counts["roi_failure"] += 1
        return
    success_by_roi = {
        str(record["roi_type"]): bool(record["roi_success"])
        for record in roi_records
    }
    core_success = all(success_by_roi.get(roi_type, False) for roi_type in args.core_roi_types)
    failed = [roi for roi, ok in success_by_roi.items() if not ok]
    warnings_by_roi = {
        str(record["roi_type"]): str(record.get("warning_list", ""))
        for record in roi_records
        if str(record.get("warning_list", ""))
    }
    status = (
        f"core_all_success={core_success}; failed={','.join(failed) or 'none'}; "
        f"warnings={warnings_by_roi or 'none'}"
    )
    categories: list[str] = []
    if image_id in random_success_ids and core_success:
        categories.append("random_success")
    if core_success:
        categories.append("core_all_success")
    if failed:
        categories.append("roi_failure")
    roi_df = pd.DataFrame(roi_records)
    for _, record in roi_df.iterrows():
        roi_type = str(record["roi_type"])
        if not bool(record.get("roi_success", False)):
            continue
        if float(record.get("padding_ratio", 0.0)) > float(args.max_padding_ratio):
            categories.append("high_padding_ratio")
        warning_list = str(record.get("warning_list", ""))
        if warning_list:
            categories.append(f"{roi_type}_warning")
    for category in dict.fromkeys(categories):
        if qc_counts[category] >= int(args.num_qc_preview):
            continue
        save_qc_preview(
            dirs[f"qc_{category}"] / f"{image_id}.png",
            image_id,
            status,
            intermediates.original_rgb,
            intermediates.aligned_rgb,
            intermediates.label_map,
            intermediates.final_face_mask,
            bboxes,
            raw_images,
            masked_images,
        )
        qc_counts[category] += 1


def validate_args(args: argparse.Namespace) -> None:
    if int(args.image_size) != 224:
        raise ValueError("This ROI script currently expects --image-size 224")
    if int(args.canvas_size) <= 0:
        raise ValueError("--canvas-size must be positive")
    if str(args.output_format).lower() != "png":
        raise ValueError("Only --output-format png is supported")
    unsupported = set(args.roi_types).difference(DEFAULT_ROI_TYPES)
    if unsupported:
        raise ValueError(f"Unsupported ROI types: {sorted(unsupported)}")
    unsupported_core = set(args.core_roi_types).difference(args.roi_types)
    if unsupported_core:
        raise ValueError(
            f"Core ROI types must be included in roi-types: {sorted(unsupported_core)}"
        )
    if not args.parsing_checkpoint.is_file():
        raise FileNotFoundError(
            f"Face parsing checkpoint does not exist: {args.parsing_checkpoint}"
        )
    if not args.split_csv.is_file():
        raise FileNotFoundError(f"Split CSV does not exist: {args.split_csv}")
    if not args.image_dir.is_dir():
        raise NotADirectoryError(f"Image directory does not exist: {args.image_dir}")


def main(argv: Sequence[str] | None = None) -> int:
    args = parse_args(argv)
    project_root = resolve_path(args.project_root, default_project_root())
    assert project_root is not None
    project_root = project_root.resolve()
    args.project_root = project_root
    args.split_csv = resolve_path(args.split_csv, project_root).resolve()
    args.image_dir = resolve_path(args.image_dir, project_root).resolve()
    args.output_dir = resolve_path(args.output_dir, project_root).resolve()
    args.global_intermediate_dir = (
        resolve_path(args.global_intermediate_dir, project_root).resolve()
        if args.global_intermediate_dir is not None
        else None
    )
    args.parsing_checkpoint = resolve_path(args.parsing_checkpoint, project_root).resolve()
    args.roi_types = parse_csv_list(args.roi_types)
    args.core_roi_types = parse_csv_list(args.core_roi_types)
    padding_color = parse_padding_color(args.padding_color)
    validate_args(args)

    random.seed(int(args.seed))
    np.random.seed(int(args.seed))
    torch.manual_seed(int(args.seed))

    split_df = load_split_table(args.split_csv, args.max_samples)
    dirs = prepare_output_dirs(args.output_dir, bool(args.overwrite))
    parsing_device = parsing.resolve_parsing_device(str(args.parsing_device))
    parsing_model = parsing.load_face_parsing_model(
        str(args.parsing_model), args.parsing_checkpoint, parsing_device
    )
    detector = mp.solutions.face_detection.FaceDetection(
        model_selection=1,
        min_detection_confidence=float(args.min_detection_confidence),
    )
    face_mesh = mp.solutions.face_mesh.FaceMesh(
        static_image_mode=True,
        max_num_faces=1,
        refine_landmarks=True,
        min_detection_confidence=float(args.min_detection_confidence),
        min_tracking_confidence=0.5,
    )

    split_rows = split_df.to_dict("records")
    random_success_ids = set(
        random.sample(
            [str(row["ID"]) for row in split_rows],
            k=min(int(args.num_qc_preview), len(split_rows)),
        )
    )
    all_roi_records: list[dict[str, Any]] = []
    sample_records: list[dict[str, Any]] = []
    failed_rows: list[dict[str, Any]] = []
    qc_counts: Counter[str] = Counter()
    try:
        total = len(split_rows)
        for index, split_row in enumerate(split_rows, start=1):
            image_id = str(split_row["ID"])
            print(f"[{index:04d}/{total:04d}] {image_id}")
            (
                roi_records,
                sample_row,
                bboxes,
                raw_images,
                masked_images,
                intermediates,
            ) = process_sample(
                split_row,
                args,
                dirs,
                detector,
                face_mesh,
                parsing_model,
                parsing_device,
                padding_color,
            )
            all_roi_records.extend(roi_records)
            sample_records.append(sample_row)
            for record in roi_records:
                if not bool(record.get("roi_success", False)):
                    failed_rows.append(
                        {
                            **base_record(split_row),
                            "roi_type": record.get("roi_type", ""),
                            "failure_reason": record.get("failure_reason", ""),
                        }
                    )
            maybe_save_qc(
                image_id,
                sample_row,
                roi_records,
                bboxes,
                raw_images,
                masked_images,
                intermediates,
                dirs,
                args,
                qc_counts,
                random_success_ids,
            )
    finally:
        face_mesh.close()
        detector.close()

    roi_df = pd.DataFrame(all_roi_records)
    sample_df = pd.DataFrame(sample_records)
    success_matrix = build_success_matrix(
        split_rows, roi_df, args.roi_types, args.core_roi_types
    )
    valid_ids = build_valid_ids(success_matrix, args.roi_types, args.core_roi_types)
    failed_df = pd.DataFrame(failed_rows)
    if failed_df.empty:
        failed_columns = [
            column for column in PRESERVE_COLUMNS if column in split_df.columns
        ]
        failed_columns.extend(["roi_type", "failure_reason"])
        failed_df = pd.DataFrame(columns=failed_columns)

    logs_dir = dirs["logs"]
    roi_df.to_csv(logs_dir / "roi_qc_metrics.csv", index=False, encoding="utf-8-sig")
    roi_df.to_csv(logs_dir / "roi_metadata.csv", index=False, encoding="utf-8-sig")
    sample_df.to_csv(logs_dir / "sample_global_status.csv", index=False, encoding="utf-8-sig")
    success_matrix.to_csv(
        logs_dir / "roi_success_matrix.csv", index=False, encoding="utf-8-sig"
    )
    valid_ids.to_csv(
        logs_dir / "multi_roi_valid_ids.csv", index=False, encoding="utf-8-sig"
    )
    failed_df.to_csv(logs_dir / "failed_cases.csv", index=False, encoding="utf-8-sig")
    summarize(
        split_df,
        roi_df,
        success_matrix,
        sample_df,
        args,
        logs_dir / "preprocess_summary.txt",
    )
    print(f"ROI metadata: {logs_dir / 'roi_metadata.csv'}")
    print(f"ROI QC metrics: {logs_dir / 'roi_qc_metrics.csv'}")
    print(f"Success matrix: {logs_dir / 'roi_success_matrix.csv'}")
    print(f"Core valid IDs: {logs_dir / 'multi_roi_valid_ids.csv'}")
    return 0


if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except (
        FileNotFoundError,
        FileExistsError,
        NotADirectoryError,
        ValueError,
    ) as exc:
        print(f"[configuration error] {exc}", file=sys.stderr)
        raise SystemExit(2) from exc
